export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const key = ([x, y]: Cell): string => `${x},${y}`;
  const live = new Set(liveCells.map(key));
  const neighborCounts = new Map<string, number>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key([x + dx, y + dy]);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }
  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && live.has(k));
  return [...neighborCounts]
    .filter(([k, count]) => survives(k, count))
    .map(([k]) => k.split(",").map(Number) as Cell);
};
